import React, { useEffect } from 'react';
import { Container } from 'react-bootstrap';
import './CustomParallax.css'; // Asegúrate de tener el archivo CSS correspondiente

const CustomParallax = ({ layers, scrollPercentage }) => {
  useEffect(() => {
    layers.forEach((layer, index) => {
      const mount = document.querySelector(`#layer${index}`);
      if (mount) {
        const speed = layer.speed;
        const initialOffset = parseFloat(layer.initialOffset?.replace('px', '') || 0);
        const fullWidth = document.body.clientWidth;
        const imageWidth = mount.offsetWidth;
        const travelDistance = fullWidth + imageWidth; // Distancia de viaje para el bucle
        const scrollPosition = (scrollPercentage / 100) * travelDistance;
        const position = (scrollPosition * speed) % imageWidth - initialOffset;
        mount.style.transform = `translateX(${position}px)`;
      }
    });
  }, [layers, scrollPercentage]);

  return (
    <div className="section_parallax">
      <Container>
        {layers.map((layer, index) => (
          <img
            key={index}
            id={`layer${index}`}
            src={layer.image}
            alt={`Layer ${index}`}
            className="parallax-layer"
          />
        ))}
        {layers.map((layer, index) => (
          <img
            key={index + layers.length}
            src={layer.image}
            alt={`Layer ${index}`}
            className="parallax-layer"
          />
        ))}
      </Container>
    </div>
  );
};

export default CustomParallax;
